279→/**
280→ * Creates multiple scored behavior records with staggered timestamps for trend testing.
281→ */
282→export async function createScoredBehaviorTrend(
283→  surreal: Surreal,
284→  workspaceId: string,
285→  identityId: string,
286→  metricType: string,
287→  definitionId: string,
288→  scores: number[],
289→): Promise<{ behaviorIds: string[] }> {
290→  const behaviorIds: string[] = [];
291→  const now = Date.now();
292→
293→  for (let i = 0; i < scores.length; i++) {
294→    const created_at = new Date(now - (scores.length - 1 - i) * 24 * 60 * 60 * 1000);
295→    const { behaviorId } = await createScoredBehaviorRecord(surreal, workspaceId, identityId, {
296→      metric_type: metricType,
297→      score: scores[i],
298→      definitionId,
299→      source_telemetry: { session_index: i },
300→      created_at,
301→    });
302→    behaviorIds.push(behaviorId);
303→  }
304→
305→  return { behaviorIds };
306→}
