118→export async function getLatestScore(
119→  surreal: Surreal,
120→  identityId: string,
121→  metricType: string,
122→): Promise<number | undefined> {
123→  const records = await listBehaviors(surreal, identityId, metricType);
124→  return records[0]?.score;
