  1→/**
  2→ * Behavior CRUD Queries
  3→ *
  4→ * Driven port implementations for behavior record persistence.
  5→ * All queries use RecordId objects per project convention.
  6→ * Behavior records are append-only -- no UPDATE queries.
  7→ */
  8→import { RecordId, type Surreal } from "surrealdb";
  9→import type { IntentEvaluationContext } from "../policy/types";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type BehaviorInput = {
 16→  metricType: string;
 17→  score: number;
 18→  sourceTelemetry: Record<string, unknown>;
 19→  workspaceId: string;
 20→  sessionId?: string;
 21→};
 22→
 23→export type BehaviorRow = {
 24→  id: RecordId<"behavior">;
 25→  metric_type: string;
 26→  score: number;
 27→  source_telemetry: Record<string, unknown>;
 28→  definition: RecordId<"behavior_definition">;
 29→  definition_version: number;
 30→  workspace: RecordId<"workspace">;
 31→  session?: RecordId<"agent_session">;
 32→  created_at: string;
 33→};
 34→
 35→export type ExhibitsEdgeRow = {
 36→  id: RecordId<"exhibits">;
 37→  in: RecordId<"identity">;
 38→  out: RecordId<"behavior">;
 39→  created_at: string;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Create Behavior Record (append-only)
 44→// ---------------------------------------------------------------------------
 45→
 46→/**
 47→ * Creates a behavior record and the exhibits edge linking identity to behavior.
 48→ * Append-only: never updates existing records.
 49→ */
 50→export async function createBehavior(
 51→  surreal: Surreal,
 52→  identityId: string,
 53→  input: BehaviorInput,
 54→): Promise<{ behaviorId: string }> {
 55→  const behaviorId = `beh-${crypto.randomUUID()}`;
 56→  const behaviorRecord = new RecordId("behavior", behaviorId);
 57→  const workspaceRecord = new RecordId("workspace", input.workspaceId);
 58→  const identityRecord = new RecordId("identity", identityId);
 59→
 60→  const content: Record<string, unknown> = {
 61→    metric_type: input.metricType,
 62→    score: input.score,
 63→    source_telemetry: input.sourceTelemetry,
 64→    workspace: workspaceRecord,
 65→    created_at: new Date(),
 66→  };
 67→
 68→  if (input.sessionId) {
 69→    content.session = new RecordId("agent_session", input.sessionId);
 70→  }
 71→
 72→  await surreal.query(`CREATE $behavior CONTENT $content;`, {
 73→    behavior: behaviorRecord,
 74→    content,
 75→  });
 76→
 77→  // Create exhibits edge: identity ->exhibits-> behavior
 78→  await surreal.query(
 79→    `RELATE $identity->exhibits->$behavior SET created_at = time::now();`,
 80→    { identity: identityRecord, behavior: behaviorRecord },
 81→  );
 82→
 83→  return { behaviorId };
 84→}
 85→
 86→// ---------------------------------------------------------------------------
 87→// Query Behavior Records
 88→// ---------------------------------------------------------------------------
 89→
 90→/**
 91→ * Lists behavior records for an identity, optionally filtered by metric type.
 92→ * Returns records ordered by created_at DESC (most recent first).
 93→ */
 94→export async function listBehaviors(
 95→  surreal: Surreal,
 96→  identityId: string,
 97→  metricType?: string,
 98→): Promise<BehaviorRow[]> {
 99→  const identityRecord = new RecordId("identity", identityId);
100→
101→  // Traverse exhibits edges from identity to behavior
102→  const edgeRows = (await surreal.query(
103→    `SELECT ->exhibits->behavior AS behaviors FROM $identity;`,
104→    { identity: identityRecord },
105→  )) as Array<Array<{ behaviors: RecordId[] }>>;
106→
107→  const behaviorIds = edgeRows[0]?.[0]?.behaviors ?? [];
108→  if (behaviorIds.length === 0) return [];
109→
110→  const query = metricType
111→    ? `SELECT * FROM behavior WHERE id IN $ids AND metric_type = $mt ORDER BY created_at DESC;`
112→    : `SELECT * FROM behavior WHERE id IN $ids ORDER BY created_at DESC;`;
113→  const rows = (await surreal.query(query, { ids: behaviorIds, mt: metricType })) as Array<BehaviorRow[]>;
114→  return rows[0] ?? [];
115→}
116→
117→/**
118→ * Gets the latest behavior score for an identity and metric type.
119→ */
120→export async function getLatestScore(
121→  surreal: Surreal,
122→  identityId: string,
123→  metricType: string,
124→): Promise<number | undefined> {
125→  const records = await listBehaviors(surreal, identityId, metricType);
126→  return records[0]?.score;
127→}
128→
129→/**
130→ * Gets the latest score per unique metric_type for an identity.
131→ * Returns a map of metric_type -> score, using the most recent record per metric.
132→ * Used for context enrichment before policy gate evaluation.
133→ */
134→export async function getLatestBehaviorScores(
135→  surreal: Surreal,
136→  identityId: string,
137→): Promise<Record<string, number>> {
138→  const allRecords = await listBehaviors(surreal, identityId);
139→
140→  // Records are already sorted by created_at DESC from listBehaviors.
141→  // Take the first (most recent) score per metric_type.
142→  const scores: Record<string, number> = {};
143→  for (const record of allRecords) {
144→    if (!(record.metric_type in scores)) {
145→      scores[record.metric_type] = record.score;
146→    }
147→  }
148→
149→  return scores;
150→}
151→
152→/**
153→ * Enriches an IntentEvaluationContext with behavior scores for an identity.
154→ * Context enrichment happens before policy gate evaluation, not inside it.
155→ * Returns a new context object (immutable -- does not mutate the input).
156→ */
157→export async function enrichBehaviorScores(
158→  surreal: Surreal,
159→  identityId: string,
160→  context: IntentEvaluationContext,
161→): Promise<IntentEvaluationContext> {
162→  const scores = await getLatestBehaviorScores(surreal, identityId);
163→  return { ...context, behavior_scores: scores };
164→}
165→
166→/**
167→ * Lists behavior records for a workspace, optionally filtered by metric type.
168→ */
169→export async function listWorkspaceBehaviors(
170→  surreal: Surreal,
171→  workspaceId: string,
172→  metricType?: string,
173→  limit = 50,
174→): Promise<BehaviorRow[]> {
175→  const workspaceRecord = new RecordId("workspace", workspaceId);
176→
177→  const query = metricType
178→    ? `SELECT * FROM behavior WHERE workspace = $ws AND metric_type = $mt ORDER BY created_at DESC LIMIT $limit;`
179→    : `SELECT * FROM behavior WHERE workspace = $ws ORDER BY created_at DESC LIMIT $limit;`;
180→  const rows = (await surreal.query(query, { ws: workspaceRecord, mt: metricType, limit })) as Array<BehaviorRow[]>;
181→  return rows[0] ?? [];
182→}
