102→/**
103→ * Creates a workspace and admin identity for dynamic behavior tests.
104→ */
105→export async function setupBehaviorWorkspace(
106→  baseUrl: string,
107→  surreal: Surreal,
108→  suffix: string,
109→): Promise<{
110→  user: TestUser;
111→  workspaceId: string;
112→  adminId: string;
113→}> {
114→  const workspaceId = `ws-${crypto.randomUUID()}`;
115→  const workspaceRecord = new RecordId("workspace", workspaceId);
116→
117→  const user = await createTestUser(baseUrl, suffix);
118→
119→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
120→    workspace: workspaceRecord,
121→    content: {
122→      name: `Dynamic Behaviors Workspace ${suffix}`,
123→      status: "active",
124→      onboarding_complete: true,
125→      onboarding_turn_count: 0,
126→      onboarding_summary_pending: false,
127→      onboarding_started_at: new Date(),
128→      created_at: new Date(),
129→    },
130→  });
131→
132→  const adminId = `id-${crypto.randomUUID()}`;
133→  const adminRecord = new RecordId("identity", adminId);
134→
135→  await surreal.query(`CREATE $identity CONTENT $content;`, {
136→    identity: adminRecord,
137→    content: {
138→      name: `Admin ${suffix}`,
139→      type: "human",
140→      identity_status: "active",
141→      workspace: workspaceRecord,
142→      created_at: new Date(),
143→    },
144→  });
145→
146→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
147→    identity: adminRecord,
148→    workspace: workspaceRecord,
149→  });
150→
151→  return { user, workspaceId, adminId };
152→}
