185→/**
186→ * Creates a behavior definition directly in the database.
187→ */
188→export async function createBehaviorDefinition(
189→  surreal: Surreal,
190→  workspaceId: string,
191→  adminId: string,
192→  opts: {
193→    title: string;
194→    goal: string;
195→    scoring_logic: string;
196→    scoring_mode: ScoringMode;
197→    telemetry_types: string[];
198→    category?: string;
199→    status?: DefinitionStatus;
200→    version?: number;
201→    enforcement_mode?: EnforcementMode;
202→    enforcement_threshold?: number;
203→  },
204→): Promise<{ definitionId: string }> {
205→  const definitionId = `def-${crypto.randomUUID()}`;
206→  const definitionRecord = new RecordId("behavior_definition", definitionId);
207→  const workspaceRecord = new RecordId("workspace", workspaceId);
208→  const adminRecord = new RecordId("identity", adminId);
209→
210→  const content: Record<string, unknown> = {
211→    title: opts.title,
212→    goal: opts.goal,
213→    scoring_logic: opts.scoring_logic,
214→    scoring_mode: opts.scoring_mode,
215→    telemetry_types: opts.telemetry_types,
216→    status: opts.status ?? "draft",
217→    version: opts.version ?? 1,
218→    enforcement_mode: opts.enforcement_mode ?? "warn_only",
219→    workspace: workspaceRecord,
220→    created_by: adminRecord,
221→    created_at: new Date(),
222→  };
223→
224→  if (opts.category !== undefined) content.category = opts.category;
225→  if (opts.enforcement_threshold !== undefined) content.enforcement_threshold = opts.enforcement_threshold;
226→
227→  await surreal.query(`CREATE $definition CONTENT $content;`, {
228→    definition: definitionRecord,
229→    content,
230→  });
231→
232→  return { definitionId };
233→}
