235→/**
236→ * Creates a behavior record scored against a definition.
237→ */
238→export async function createScoredBehaviorRecord(
239→  surreal: Surreal,
240→  workspaceId: string,
241→  identityId: string,
242→  opts: {
243→    metric_type: string;
244→    score: number;
245→    definitionId: string;
246→    definition_version?: number;
247→    source_telemetry?: Record<string, unknown>;
248→    created_at?: Date;
249→  },
250→): Promise<{ behaviorId: string }> {
251→  const behaviorId = `beh-${crypto.randomUUID()}`;
252→  const behaviorRecord = new RecordId("behavior", behaviorId);
253→  const workspaceRecord = new RecordId("workspace", workspaceId);
254→  const identityRecord = new RecordId("identity", identityId);
255→  const definitionRecord = new RecordId("behavior_definition", opts.definitionId);
256→
257→  await surreal.query(`CREATE $behavior CONTENT $content;`, {
258→    behavior: behaviorRecord,
259→    content: {
260→      metric_type: opts.metric_type,
261→      score: opts.score,
262→      source_telemetry: opts.source_telemetry ?? {},
263→      definition: definitionRecord,
264→      definition_version: opts.definition_version ?? 1,
265→      workspace: workspaceRecord,
266→      created_at: opts.created_at ?? new Date(),
267→    },
268→  });
269→
270→  // Create exhibits edge: identity -> behavior
271→  await surreal.query(
272→    `RELATE $identity->exhibits->$behavior SET added_at = time::now();`,
273→    { identity: identityRecord, behavior: behaviorRecord },
274→  );
275→
276→  return { behaviorId };
277→}
