import { RecordId, type Surreal } from "surrealdb";
import type { IntentEvaluationContext } from "../policy/types";
import type {
  BehaviorDefinitionRecord,
  CreateBehaviorDefinitionInput,
  UpdateBehaviorDefinitionInput,
  DefinitionStatus,
} from "./definition-types";

input.old_string:
